// Re-run the 9 gates client-side. Defense-in-depth: the n8n-blog-ingest Edge Function and the DB validate_blog_post trigger run the same gates.
const payload = JSON.parse($input.first().json.text);
const BANLIST = ['rent collection','online rent','autopay','auto-pay','tenant portal','automated rent','collect rent','rent processing','pay rent online','online payments','online rent payment','rent collection software','tenants can pay','pay rent through','automated workflow','rent tracking','mobile app access','record rent','paid rent','pay rent'];
const SLUG = /^[a-z][a-z0-9]*(-[a-z0-9]+)*$/;
const CATS = ['lease-law','tax-prep','tenant-screening','maintenance','software-vault'];
const failures = [];
const wc = (payload.content||'').trim().split(/\s+/).filter(Boolean).length;
if (wc < 1200 || wc > 3000) failures.push({gate:'word_count', message:String(wc)});
const h2 = ((payload.content||'').match(/^## /gm)||[]).length;
if (h2 < 4 || h2 > 10) failures.push({gate:'h2_count', message:String(h2)});
if (!/landlord/i.test(payload.content||'')) failures.push({gate:'persona_phrase', message:'missing'});
if (!SLUG.test(payload.slug||'') || (payload.slug||'').length<3 || (payload.slug||'').length>120) failures.push({gate:'slug_pattern', message:payload.slug});
if (!payload.meta_description || payload.meta_description.length < 50 || payload.meta_description.length > 160) failures.push({gate:'meta_length', message:String(payload.meta_description && payload.meta_description.length)});
if (!payload.excerpt || payload.excerpt.length < 80 || payload.excerpt.length > 200) failures.push({gate:'excerpt_length', message:String(payload.excerpt && payload.excerpt.length)});
if (!CATS.includes(payload.category)) failures.push({gate:'category', message:payload.category});
const lower = (payload.content||'').toLowerCase();
for (const p of BANLIST) { if (lower.includes(p)) { failures.push({gate:'banlist', message:p}); break; } }
const doc = ((payload.content||'').match(/DocuSeal/gi)||[]).length;
if (doc > 1) failures.push({gate:'docuseal_mention', message:String(doc)});
if (payload.canonical_url !== undefined && typeof payload.canonical_url === 'string') { if (!payload.canonical_url.startsWith('/') && !payload.canonical_url.startsWith('https://')) failures.push({gate:'canonical_url_format', message:payload.canonical_url}); }
return [{json: {ok: failures.length===0, payload, gate_failures: failures}}];
